import anthropic

client = anthropic.Anthropic()

db_tools = [
    {
        "name": "get_schema",
        "description": "Return the database schema as SQL CREATE TABLE statements. Call this first to understand the available tables and columns.",
        "input_schema": {"type": "object", "properties": {}},
    },
    {
        "name": "execute_query",
        "description": "Execute a read-only SQL SELECT query and return the results as JSON.",
        "input_schema": {
            "type": "object",
            "properties": {
                "sql": {
                    "type": "string",
                    "description": "A valid SQL SELECT statement. Only SELECT is allowed.",
                },
            },
            "required": ["sql"],
        },
    },
]

def run_database_agent(question: str) -> str:
    messages = [{"role": "user", "content": question}]
    system = (
        "You are a database analyst. "
        "Use get_schema to understand the database structure, "
        "then use execute_query to run SQL queries to answer the user's question. "
        "Write correct SQL based on the actual schema. "
        "Summarize the query results in plain language."
    )
    while True:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=system,
            tools=db_tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return "Done."

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                if block.name == "get_schema":
                    result = get_schema()
                elif block.name == "execute_query":
                    result = execute_query(block.input["sql"])
                else:
                    result = f"Unknown tool: {block.name}"
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})

answer = run_database_agent(
    "Which product category has the highest total sales revenue?"
)
print(answer)
