import sqlite3, json

def execute_write(sql: str, dry_run: bool = True) -> dict:
    """
    Execute a write SQL statement (INSERT, UPDATE, DELETE).
    If dry_run=True, validate the SQL without committing.
    Returns: {'rows_affected': N, 'dry_run': bool, 'error': str|None}
    """
    sql_upper = sql.strip().upper()
    # Whitelist: only allow specific write operations
    allowed_ops = ("INSERT INTO", "UPDATE ", "DELETE FROM")
    if not any(sql_upper.startswith(op) for op in allowed_ops):
        return {"rows_affected": 0, "dry_run": dry_run,
                "error": "Only INSERT, UPDATE, and DELETE are allowed."}
    # Block dangerous patterns
    if "DROP" in sql_upper or "TRUNCATE" in sql_upper or "ALTER" in sql_upper:
        return {"rows_affected": 0, "dry_run": dry_run,
                "error": "DDL statements are not allowed."}
    try:
        conn = sqlite3.connect(DB_PATH)
        cursor = conn.execute(sql)
        rows_affected = cursor.rowcount
        if dry_run:
            conn.rollback()  # validate but do not commit
        else:
            conn.commit()
        conn.close()
        return {"rows_affected": rows_affected, "dry_run": dry_run, "error": None}
    except sqlite3.Error as e:
        return {"rows_affected": 0, "dry_run": dry_run, "error": str(e)}

# Agent proposes SQL in dry_run mode → show to user → execute for real
proposal = execute_write(
    "UPDATE products SET stock_quantity = stock_quantity - 1 WHERE id = 2",
    dry_run=True,
)
print(f"Dry run: would affect {proposal['rows_affected']} row(s)")
if proposal["rows_affected"] > 0 and not proposal["error"]:
    user_approved = True  # In production: prompt the user
    if user_approved:
        result = execute_write(
            "UPDATE products SET stock_quantity = stock_quantity - 1 WHERE id = 2",
            dry_run=False,
        )
        print(f"Executed: {result['rows_affected']} row(s) updated")
